css:
@import url("https://fontsapi.zeoseven.com/287/main/result.css");

body {
    font-family: "Source Han Serif SC VF";
    font-weight: normal;
}
/* -----Moaisha❥----- */

 /* 全局去除所有元素的阴影效果 */
* {
    box-shadow: none !important;
    filter: none !important;
}
body.bubblechat .welcomePanel
 {
    border-radius: 0px;
    background-color: var(--SmartThemeBotMesBlurTintColor);
    border: 1px solid var(--SmartThemeBorderColor);
    margin-bottom: 5px;
}
/* ==== 1. 背景 ==== */
.text_pole,
textarea {
    border-radius: 15px;
    background: linear-gradient(145deg, #ffffff, #E3EFFF);
    color: #000000;
}
.wide_dialogue_popup {
    background-image: url('https://files.catbox.moe/im5vzu.jpeg');
    background-size: cover; 
    background-position: center;
    background-repeat: no-repeat; 
border: 3px solid #cce5eb;
}
/* ==== 2. 删除按钮及相关样式 ==== */
#delete_button, .redWarningBG, .menu_button.popup-button-ok {
    color: #;
    background: #fff;
    font-size: 12px;
   border-radius: 5px;
     border-top: none;
    border-left: none;
    border-right: 4px solid #CEE0F6;
    border-bottom: 5px solid #BED7F7;

}   
/* ==== 3. 顶部组件样式 ==== */
body.no-blur #top-bar,
.drawer {
    background-image: url('https://files.catbox.moe/k5z8ns.jpg');
    background-size: cover;
    background-position: center;

} 
/* ==== 4. UI样式 ==== */
.drawer-content {
    background-image: url('https://files.catbox.moe/euidns.png');
    background-size: cover;
    background-position: center;
    background-repeat: no-repeat;
}    
.note-link-span {
    background: linear-gradient(145deg,#a1e6fe, rgba(255, 255, 255, 1));
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;

}
.drawer-content {
    border:none;
border-radius: 0 0 15px 15px !important;
}
.mes_button, .extraMesButtons>div {
    cursor: pointer;
    transition: opacity 0.2s ease-in-out;
    filter: drop-shadow(0px 0px 2px black);
    opacity: 0.3;
    padding: 1px 3px;
    z-index: 10;
}
/* ==== 5. 调节组件样式 ==== */
.neo-range-input {
    background: linear-gradient(180deg, #cce5eb, rgba(255, 255, 255, 0.9));
}
input[type="range"] {
    -webkit-appearance: none;
    width: 100%;
    background: #fff; 
    height: 10px; 
    box-sizing: border-box;
    display: block; 
}
input[type="range"]::-webkit-slider-thumb {
    -webkit-appearance: none;
    width: 30px;
    height: 30px;
    border: none; 
    border-radius: 100%;
    background: url('https://files.catbox.moe/msorfl.png'); 
    background-size: contain; 
    background-repeat: no-repeat;
    cursor: pointer;
    transition: all 0.2s ease;
    box-shadow: none;
}
/* ==== 6. 调节组件样式 ==== */
.inline-drawer-header {
    background: linear-gradient(14deg, #cce5eb, rgba(255, 255, 255, 0.9));
    padding: 0px;
    margin: 2px;
    position: relative; 
    border-top: none;
    border-left: none;
    border-right: 4px solid #CEE0F6;
    border-bottom: 5px solid #BED7F7;
    overflow: visible;
}

.inline-drawer-header::before {
    content: "";
    position: absolute;
    top: -13px;
    left: -7px;
    width: 40px; 
    height: 25px; 
    background-image: url('https://files.catbox.moe/qf5977.png'); 
    background-size: cover;
    background-repeat: no-repeat;
}  
input[type='checkbox'] {
    border-radius: 4px;
    border: none;
    background: linear-gradient(to bottom, #CEE0F6, rgba(255, 255, 255, 1)) !important;
    backdrop-filter: blur(4px);
    outline:none;
    width: 15px;
    height: 15px;
    border: 1px solid #BED7F7 !important;
    box-shadow: 
        inset 1px 1px 0 #ffffff,
        inset -1px -1px 0 #BED7F7,
        4px 3px 0 #CEE0F6!important;
} 
input[type="checkbox"]:checked {
    background: linear-gradient(-75deg,#CEE0F6, #BED7F7) !important;
color: transparent!important;
}
input[type="checkbox"]::before {
    content: '';
    position: absolute;
    top: -10px;  
}  
.userSettingsInnerExpandable {
    border: 3px solid #cce5eb;
    border-radius: 10px;

}
.userSettingsInnerExpandable {
    border-top: none;
    border-left: none;
    border-right: 4px solid #CEE0F6;
    border-bottom: 5px solid #BED7F7;
    border-radius: 0px;
}
.range-block-counter input {
    display: block;
    cursor: text;
 color: #000;
    background: linear-gradient(14deg, #cce5eb, rgba(255, 255, 255, 0.9));
    border-top: none;
    border-left: none;
    border-right: 4px solid #CEE0F6;
    border-bottom: 5px solid #BED7F7;
    border-radius: 0px;
    padding: 2px;
    flex: 1;
    text-align: center;
    width: 70px;
}

[data-i18n="Prompts"] {
    background: linear-gradient(14deg,#cce5eb, rgba(255, 255, 255, 0.9));
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent; 
}
.range-block-counter input {
    display: block;
    cursor: text;
 color: #000 ;
    background: linear-gradient(14deg, #cce5eb, rgba(255, 255, 255, 0.9));
    border-top: none;
    border-left: none;
    border-right: 4px solid #DBEBFF;
    border-bottom: 5px solid #FFFFFF;
    border-radius: 0px;
    padding: 2px;
    flex: 1;
    text-align: center;
    width: 70px;
}
/* ==== 7. 展开按钮样式 ==== */
.custom-drawer-icon,
.inline-drawer-icon {
    filter: none;
    background-image: linear-gradient(45deg,#B2D4FF, #cce5eb); 
    -webkit-background-clip: text;
    background-clip: text;
    -webkit-text-fill-color: transparent;
    text-fill-color: transparent;
}    


/* ==== 1. 下拉选择框样式 ==== */
select {
    background: linear-gradient(145deg,#fff , #cce5eb);
    padding: 5px 10px;
    border-radius: 5px;
    transition: background 0.3s ease;
    color:#000;
    border: none !important;
}    
select option:not(:checked) {
    color: #fff;
}
select option:checked {
    color:#fff ;
    background-color:#B4D5FF!important;
}
select option {
    background-color:#B4D5FF !important;
}

.title_restorable {
    background-image: none !important;
}

#extensions_settings .inline-drawer-toggle.inline-drawer-header, 
#extensions_settings2 .inline-drawer-toggle.inline-drawer-header, 
#user-settings-block h4, 
.standoutHeader {
    background-image: none !important;
    background:#E3EFFF;
    border-top: none;
    border-left: none;
    border-right: 4px solid #fff;
    border-radius: 0px;
    color: rgba(86, 112, 144, 0.81) ;
    text-shadow: 1px 1px 2px rgba(197, 233, 245, 0.5);
}

/* ==== 2. Select2 插件相关样式 ==== */
.select2_multi_sameline+span.select2-container .select2-selection--multiple {
    color:  #000;
    background-color:#DBEBFF;
}
.select2-container .select2-results>.select2-results__options {
    background-color:#DBEBFF ;
}
.select2_multi_sameline+span.select2-container .select2-selection--multiple .select2-selection__choice,
.select2_choice_clickable+span.select2-container .select2-selection__choice__display,
span.select2.select2-container .select2-selection__choice__remove {
    color:#DBEBFF;
    background-color:  #fff ;
}

/* ==== 3. 菜单按钮样式 ==== */
.menu_button {
    color: #371616 ;
    background: linear-gradient(145deg,#cce5eb,  #fff);    border-top: none;
    border-left: none;
    border-right: 4px solid #D7E8FF;
    border-bottom: 5px solid #fff;
    border-radius: 0px;
    filter: none;
}
.text_pole, textarea {
    color: rgb(0, 0, 0);
font-family: "Source Han Serif SC VF";
    border-radius: 15px;
    background: linear-gradient(145deg, rgb(255, 255, 255), rgb(227, 239, 255));
}

/* ==== 1. 输入框及样式 ==== */
#send_form {
    border-radius: 15px !important;
    background:linear-gradient(180deg,rgba(255, 255, 255, 1),#DBEBFF);
    border-top: none;
    border-left: none;
    border-right: 4px solid #B4D5FF;
    border-bottom:4px solid #fff;
}
#send_textarea:placeholder-shown {
    font-family: "Source Han Serif SC VF";
    font-weight: normal;
    font-size: 15px;
    background-color:#DBEBFF;
}
#send_textarea {
    border-top: none;
    border-left: none;
    border-right: 4px solid #fff;
    border-bottom:4px solid #fff;
    outline: none;
    box-sizing: border-box;
    border-radius:15px;
}

#completion_prompt_manager #completion_prompt_manager_list {
    border-top: none;
    border-left: none;
    border-right: 4px solid #E3EFFF;
    border-bottom:4px solid #B4D5FF;
}
/* ==== 2. 预设样式 ==== */
#completion_prompt_manager #completion_prompt_manager_list li.completion_prompt_manager_prompt span span span {
   filter: none;
}
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_disabled .completion_prompt_manager_prompt_name .prompt-manager-inspect-action,
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_name .prompt-manager-inspect-action {
    font-size: 13px;
}
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_disabled .completion_prompt_manager_prompt_name .prompt-manager-inspect-action {
    color:#313d4d;
}
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_name .prompt-manager-inspect-action {
    color:#313d4d;
}
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_disabled .completion_prompt_manager_prompt_name .prompt-manager-inspect-action:hover {
    color:#313d4d;

}
#completion_prompt_manager #completion_prompt_manager_list li.completion_prompt_manager_prompt {
    align-items: center;
    padding: 0em;
    border-left: 3px solid #D2E6FE; 

}    
#completion_prompt_manager #completion_prompt_manager_list li.completion_prompt_manager_list_head .prompt_manager_prompt_tokens, 
#completion_prompt_manager #completion_prompt_manager_list li.completion_prompt_manager_prompt .prompt_manager_prompt_tokens {
    font-size: calc(var(--mainFontSize)* 0.9);
    text-align: right;
    color:  #313d4d;
}
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt:not(.completion_prompt_manager_prompt_disabled) .prompt-manager-toggle-action {
    color:#313d4d;

}
span.prompt-manager-toggle-action.fa-solid.fa-toggle-off {
    color:#92C2FE;

}      
span[title="edit"].prompt-manager-edit-action.fa-solid.fa-pencil.fa-xs {
    background-image: url('https://files.catbox.moe/k5ab0m.png');
    background-size:18px; 
    background-position: center;
    background-repeat: no-repeat; 
    color: transparent;
    filter: none!important;
} 

/* ==== 4. 编辑框样式 ==== */
/* 编辑框 */
.edit_textarea {
    color:#B5D6FF ;
  border: 1px solid #D5E8FF; 
}

/* ==== 5. 警告信息样式 ==== */
/* 隐藏代理警告 */
#ReverseProxyWarningMessage { 
    display: none !important; 
}

/* ==== 6. 标注区域样式 ==== */
.mes_text blockquote {
    background-color: #9BC3F7;
    border-left: 5px solid #7d1d8b; 
    color: #fff; 
}
/* ==== 1. 角色切换器样式 ==== */
/* 角色切换器优化 */
#HotSwapWrapper > div {
    padding: 2px 0;
}
.character_select {
    transition: transform 0.3s ease;

    border-radius: 5px;
}
.character_select:hover {
    transform: translateY(-5px);

}

/* ==== 2. 样式 ==== */
body.waifuMode #chat {
    border-radius: 12px 12px 0 0;
    border-top: 1px solid  rgba(255, 255, 255, 0.1);
    border-left: 1px solid  rgba(255, 255, 255, 0.1); 
    border-right: 1px solid rgba(255, 255, 255, 0.1); 
    border-bottom: none;
    background-color: rgba(255, 255, 255, 0.1);
}

body.waifuMode #top-bar {
    height: 0px;
    border: none;
    box-shadow: none; 
    background-color:rgba(255, 255, 255, 0.8);
}
body.waifuMode #top-settings-holder {
    background-color: transparent;
    opacity: 0;
    max-height: 30px;
    pointer-events: all; 
    transition: opacity 1.0s ease, visibility 1.0s ease, max-height 1.0s ease, pointer-events 0s ease;
}
body.waifuMode #top-settings-holder:hover {
    opacity: 1;
    visibility: visible;
    max-height: 80px;
    pointer-events: auto; 
    background-color: rgba(255, 255, 255, 0.8);
}

#extensionTopBar {
    color:#A3CCFE;
   border-radius:0px!important;

}
#extensionConnectionProfilesSelect {
    color: #A3CCFE; 
}
/* ==== 3. 二维码按钮样式 ==== */
#qr--bar > .qr--buttons .qr--button,
#qr--popout > .qr--body > .qr--buttons .qr--button {  
    font-size: 12px;
    transition: all 0.2s;
    border-radius: 5px;
    color:  #A3CCFE!important;
    border: 2px solid  #A3CCFE!important;
    border-radius: 10px;
}
#qr--bar > .qr--buttons .qr--button:hover,
#qr--popout > .qr--body > .qr--buttons .qr--button:hover {
    transform: translateY(-1px); 
color: #A3CCFE!important;
}
.red_button, .redWarningBG {
    background-color: #A3CCFE !important;
}
#extensionsMenu>.extension_container>div, #extensionsMenu>div:not(.extension_container), .options-content a, .list-group-item {
     color:#313d4d;
    background-image: url('https://files.catbox.moe/im5vzu.jpeg');
    background-size: cover; 
    background-position: center;
    background-repeat: no-repeat;
filter: none;
}
/* ==== 6. 滚动条样式 ==== */

::-webkit-scrollbar {
  width: 3px;
}

::-webkit-scrollbar:horizontal {
  height: 15px;
}

::-webkit-scrollbar-track {
  background: transparent;
}

::-webkit-scrollbar-thumb:vertical,
::-webkit-scrollbar-thumb:horizontal {
  background-color: color-mix(in srgb, #A3CCFE
 80%, transparent);
  box-shadow: none;
  border: 0;
}
/* ==== 3. 代码块文本样式 ==== */
.mes_text pre code,
.mes_reasoning pre code {
    color: #313d4d !important;
    font-family:  "Source Han Serif SC VF";
    position: relative; 
}
.markdown-body code,
code {
    position: relative;
    display: inline-block;
    padding: 0.4em 1.2em;
    margin: 0 0.2em;
    border-radius: 4px;
    color: #313d4d !important;
    font-family:  "Source Han Serif SC VF";
    background: linear-gradient(180deg, #A3CCFE, #FFFFFF) !important;
    border: 0;
    box-shadow: inset 0 0 8px rgba(154, 87, 173, 0.3), 0 2px 4px rgba(0, 0, 0, 0.2);
    border: 1px solid #bcd3ff !important;
}

/* 引用样式 */
.mes q {
    display: inline-block;
    padding: 2px 2px;
    margin: 2px 10px 2px 0px;
    background:  #fff!important;
    border-top: 2px dashed  #A3CCFE !important;;
    border-left: 2px dashed #A3CCFE;
    border-right: 2px inset #A3CCFE;
    border-bottom: 2px inset #A3CCFE;
    border-radius: 5px;
    box-shadow:
        5px 5px 0 #A3CCFE,
        inset 1px 1px 2px rgba(255, 255, 255, 0.5);
    animation: quoteShimmer 2s infinite;
    transition: all 0.3s ease;
}

.mes q:active {
    transform: scale(0.98);
    box-shadow:
        5px 5px 0#A3CCFE,
        inset 1px 1px 2px rgba(255, 255, 255, 0.5);
    background: #A3CCFE;
}

.mes q:hover {
    color: #A3CCFE;
    text-shadow: 1px 1px #ffffff, 2px 2px #A3CCFE;

}

@keyframes quoteShimmer {
    0% {
        background-color: var(--quote-bg-color-start);
    }
    50% {
        background-color: var(--quote-bg-color-middle);
    }
    100% {
        background-color: var(--quote-bg-color-start);
    }
}













































