 background:#cce5eb ;

}

/* ==== 8. 头像框样式 ==== */
.avatar img {
    width: 50px !important;
    height: 50px !important;
    border-radius: 50% !important;
    border: 3px solid rgba(188, 211, 255, 1);
top：50px;
}

div.avatar img {
    box-shadow: 0 0 0 2px 
    color-mix(in srgb, rgba(255, 255, 255, 0.5) 60%, transparent), 0 0 10px 2px 
    color-mix(in srgb, rgba(223, 234, 254, 1) 60%, transparent) !important;
}
@keyframes moveUp {
    0% {
        transform: translateY(0);
    }
    50% {
        transform: translateY(-5px); 
    }
    100% {
        transform: translateY(0);
    }
}

@keyframes moveDown {
    0% {
        transform: translateY(0);
    }
    50% {
        transform: translateY(5px);
    }
    100% {
        transform: translateY(0);
    }
}

body.bubblechat .mes[is_user="true"] .avatar::before {
    content: '';
    position: absolute;
    top: 20px;
    left: -5px;
    width: 40px;
    height: 45px;
    background-image: url('https://files.catbox.moe/olvn8h.png');
    background-size: cover;
    background-repeat: no-repeat;
    border-radius: 0%;
    animation: moveDown 2.5s ease-in-out infinite;  
}

body.bubblechat .mes[is_user="false"] .avatar::before {
    content: '';
    position: absolute;
    top: -1px;
    left: 40px;
    width: 35px;
    height: 32px;
    background-image: url('https://files.catbox.moe/altkt7.png');
    background-size: cover;
    animation: moveUp 2.5s ease-in-out infinite;
}

